from azure.ai.projects import AgentTool

@AgentTool(name="generate_draft", description="Generate professional email response")
def generate_draft(to: str, subject: str, context: str) -> str:
    prompt = f"""
    Generate professional response to: {subject}
    Context: {context}
    To: {to}
    """
    response = openai.chat.completions.create(
        model="gpt-4o",
        messages=[{"role": "user", "content": prompt}]
    )
    return response.choices[0].message.content

# Register with agent
thread.add_tools([generate_draft])

