import { VexClient } from 'vex-sdk';

const vex = new VexClient({ apiKey: process.env.VEX_API_KEY });

async function validateRecipients(recipients: string[]): Promise<boolean> {
  const result = await vex.verify({
    input: { to: recipients, cc: [], bcc: [] },
    policy: 'recipient-validation',
    config: {
      allowedDomains: ['company.com', 'partner.com'],
      blockExternal: true,
      execProtection: true
    }
  });

  return result.status === 'approved';
}

